  { id: 5, title: "Playwright: Llenar Formularios", stars: 3, category: "PLAYWRIGHT", description: "Interactúa con inputs y botones usando locators de Playwright.", objective: "page.fill() y page.click()", tags: ["fill", "click", "locator"], fileName: "form.spec.ts", completed: false, explanationText: "Playwright recomienda locators semánticos como getByRole y getByLabel para tests más resilientes.", codeSnippet: "test('login', async ({ page }) => {\n  await page.goto('/login');\n  await page.[INPUT_1]('[data-testid=email]', 'iram@test.com');\n  await page.fill('[data-testid=pass]', 'secret');\n  await page.[INPUT_2]('[data-testid=submit]');\n  await expect(page).toHaveURL(/[INPUT_3]/);\n});", inputs: { INPUT_1: "fill", INPUT_2: "click", INPUT_3: "dashboard" }, completeCode: "await page.fill(selector, value);\nawait page.click(selector);" },
  { id: 6, title: "Playwright: Mocking de API Routes", stars: 4, category: "PLAYWRIGHT", description: "Intercepta y mockea respuestas de API con page.route().", objective: "page.route() para mock de red", tags: ["route", "fulfill", "mock"], fileName: "mock.spec.ts", completed: false, explanationText: "page.route() intercepta peticiones y permite retornar respuestas mockeadas con route.fulfill().", codeSnippet: "await page.[INPUT_1]('/api/users', async route => {\n  await route.[INPUT_2]({\n    [INPUT_3]: 'application/json',\n    body: JSON.stringify([{ id: 1, name: 'Test' }])\n  });\n});", inputs: { INPUT_1: "route", INPUT_2: "fulfill", INPUT_3: "contentType" }, completeCode: "await page.route('/api/users', async route => {\n  await route.fulfill({ contentType: '...', body: '...' });\n});" },
  { id: 7, title: "Cypress: data-testid Best Practice", stars: 2, category: "CYPRESS", description: "Usa selectores estables con data-testid. Caso real: tests E2E que no se rompen al cambiar clases CSS de Vuetify.", objective: "Selectores resilientes", tags: ["data-testid", "selectors", "best practice"], fileName: "dashboard.cy.ts", completed: false, explanationText: "Evita selectores frágiles (.btn-primary, .v-btn). data-testid es el estándar en equipos que usan Cypress y Playwright.", codeSnippet: "<!-- Componente Vue -->\n<v-btn [INPUT_1]=\"submit-order\">Confirmar</v-btn>\n\n// Test Cypress\ncy.get('[data-testid=[INPUT_2]]').click();\ncy.get('[data-testid=order-success]').should('be.[INPUT_3]');", inputs: { INPUT_1: "data-testid", INPUT_2: "submit-order", INPUT_3: "visible" }, completeCode: "data-testid=\"submit-order\" | cy.get('[data-testid=submit-order]')" },
  { id: 8, title: "Playwright: getByRole Accesible", stars: 3, category: "PLAYWRIGHT", description: "Usa locators semánticos para tests accesibles. Caso real: cumplir WCAG en apps Material Design/Vuetify.", objective: "getByRole y getByLabel", tags: ["getByRole", "a11y", "semantic"], fileName: "a11y.spec.ts", completed: false, explanationText: "getByRole('button', { name: 'Guardar' }) prueba accesibilidad y funcionalidad a la vez. Recomendado por Playwright sobre CSS selectors.", codeSnippet: "test('submit form', async ({ page }) => {\n  await page.goto('/form');\n  await page.[INPUT_1]('textbox', { name: 'Email' }).fill('test@test.com');\n  await page.getByRole('[INPUT_2]', { name: 'Enviar' }).click();\n  await expect(page.getByRole('[INPUT_3]')).toContainText('Guardado');\n});", inputs: { INPUT_1: "getByRole", INPUT_2: "button", INPUT_3: "alert" }, completeCode: "getByRole('textbox') | getByRole('button') | getByRole('alert')" },
  { id: 9, title: "Cypress: Component Testing Vue", stars: 4, category: "CYPRESS", description: "Prueba componentes Vue aislados con Cypress CT. Caso real: validar formularios Vuetify sin levantar toda la app.", objective: "cy.mount() para component tests", tags: ["component testing", "cy.mount", "Vue"], fileName: "LoginForm.cy.ts", completed: false, explanationText: "Cypress Component Testing monta componentes individuales. Complementa Vitest/VTU para tests visuales con DOM real.", codeSnippet: "import LoginForm from './LoginForm.vue';\n\ndescribe('LoginForm', () => {\n  it('validates email', () => {\n    cy.[INPUT_1](LoginForm);\n    cy.get('[data-testid=email]').type('invalid');\n    cy.get('[data-testid=submit]').click();\n    cy.contains('[INPUT_2]').should('be.visible');\n  });\n});", inputs: { INPUT_1: "mount", INPUT_2: "Email inválido" }, completeCode: "cy.mount(LoginForm) | cy.contains('Email inválido')" },
  { id: 10, title: "Playwright: E2E en CI (GitHub Actions)", stars: 4, category: "CI/CD", description: "Ejecuta tests E2E en pipeline CI. Caso real: bloquear merge a main si fallan tests de flujos críticos.", objective: "playwright test en CI", tags: ["CI", "GitHub Actions", "headless"], fileName: "e2e.yml", completed: false, explanationText: "Playwright en CI corre headless con retries. Integra con GitHub Actions para correr en cada PR.", codeSnippet: "# .github/workflows/e2e.yml\n- name: Install Playwright\n  run: npx [INPUT_1] install --with-deps\n\n- name: Run E2E tests\n  run: npx [INPUT_2] test\n\n- uses: actions/upload-artifact@v4\n  if: failure()\n  with:\n    name: [INPUT_3]\n    path: playwright-report/", inputs: { INPUT_1: "playwright", INPUT_2: "playwright", INPUT_3: "playwright-report" }, completeCode: "npx playwright install | npx playwright test | upload playwright-report on failure" }
